using System.IdentityModel.Tokens.Jwt; using System.Security.Claims; using System.Security.Cryptography; using System.Text; using ExpenseTracker.Application.Interfaces; using ExpenseTracker.Domain.Entities; using Microsoft.Extensions.Configuration; using Microsoft.IdentityModel.Tokens;
namespace ExpenseTracker.Infrastructure.Identity;
public sealed class JwtService(IConfiguration config):ITokenService { public string CreateAccessToken(User user){var key=new SymmetricSecurityKey(Encoding.UTF8.GetBytes(config["Jwt:Key"]!));var token=new JwtSecurityToken(claims:[new Claim(JwtRegisteredClaimNames.Sub,user.Id.ToString()),new Claim(JwtRegisteredClaimNames.Email,user.Email)],expires:DateTime.UtcNow.AddMinutes(15),signingCredentials:new SigningCredentials(key,SecurityAlgorithms.HmacSha256));return new JwtSecurityTokenHandler().WriteToken(token);} public string CreateRefreshToken()=>Convert.ToBase64String(RandomNumberGenerator.GetBytes(64)); }
public static class PasswordHasher { public static string Hash(string value)=>BCrypt.Net.BCrypt.HashPassword(value); public static bool Verify(string value,string hash)=>BCrypt.Net.BCrypt.Verify(value,hash); }
